import React, { useState, useEffect, useRef } from 'react';
import RecommendCard from '../components/RecommendCard';
import './Recommend.css';

export default function Recommend() {
  const [query,    setQuery]    = useState('');
  const [titles,   setTitles]   = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [showDrop, setShowDrop] = useState(false);
  const [results,  setResults]  = useState(null);
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    fetch('http://127.0.0.1:5000/api/titles')
      .then(r => r.json())
      .then(setTitles)
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (query.length < 2) { setFiltered([]); return; }
    const q = query.toLowerCase();
    setFiltered(titles.filter(t => t.toLowerCase().includes(q)).slice(0, 8));
  }, [query, titles]);

  const selectTitle = (t) => {
    setQuery(t);
    setFiltered([]);
    setShowDrop(false);
  };

  const handleSubmit = async (e) => {
    e?.preventDefault();
    if (!query.trim()) return;
    setLoading(true);
    setError('');
    setResults(null);
    try {
      const res  = await fetch('http://127.0.0.1:5000/api/recommend', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ book: query }),
      });
      const data = await res.json();
      if (!res.ok) setError(data.error || 'Something went wrong.');
      else         setResults(data);
    } catch {
      setError('Could not connect to Flask. Is it running on port 5000?');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="rec-page">

      {/* ═══════════════════════════════
           CINEMATIC BANNER
      ═══════════════════════════════ */}
      <section className="rec-banner">
        {/* Noise texture overlay */}
        <div className="rec-banner__noise" />
        <div className="rec-banner__glow rec-banner__glow--1" />
        <div className="rec-banner__glow rec-banner__glow--2" />

        <div className="container rec-banner__content">

          <div className="rec-banner__label">
            <span className="rec-banner__dot" />
            Collaborative Filtering Engine
          </div>

          <h1 className="rec-banner__title">
            Find Books<br />
            <em>Like This One</em>
          </h1>
          <p className="rec-banner__sub">
            Enter any book title and we'll surface four similar reads based
            on shared reader preferences across 270K+ ratings.
          </p>

          {/* Search */}
          <div className="rec-search-wrap" ref={inputRef}>
            <form className="rec-search" onSubmit={handleSubmit}>
              <div className="rec-search__field">
                <span className="rec-search__icon">🔍</span>
                <input
                  type="text"
                  className="rec-search__input"
                  placeholder="e.g. Harry Potter and the Chamber of Secrets"
                  value={query}
                  onChange={e => { setQuery(e.target.value); setShowDrop(true); }}
                  onFocus={() => setShowDrop(true)}
                  onBlur={() => setTimeout(() => setShowDrop(false), 180)}
                  autoComplete="off"
                />
                {query && (
                  <button
                    type="button"
                    className="rec-search__clear"
                    onClick={() => { setQuery(''); setResults(null); setError(''); }}
                  >✕</button>
                )}

                {/* Autocomplete dropdown */}
                {showDrop && filtered.length > 0 && (
                  <ul className="rec-dropdown">
                    {filtered.map(t => (
                      <li key={t} onMouseDown={() => selectTitle(t)}>
                        <span className="rec-dropdown__icon">📖</span>
                        <span>{t}</span>
                      </li>
                    ))}
                  </ul>
                )}
              </div>

              <button
                type="submit"
                className="rec-search__btn"
                disabled={loading || !query.trim()}
              >
                {loading
                  ? <span className="rec-spinner" />
                  : <>▶ Recommend</>
                }
              </button>
            </form>
          </div>

        </div>
      </section>

      {/* ═══════════════════════════════
           RESULTS
      ═══════════════════════════════ */}
      <section className="rec-results">
        <div className="container">

          {/* Error */}
          {error && (
            <div className="rec-error fade-up">
              <span className="rec-error__icon">⚠️</span>
              <div>
                <strong>Something went wrong</strong>
                <p>{error}</p>
              </div>
            </div>
          )}

          {/* Loading skeletons */}
          {loading && (
            <div className="rec-grid">
              {Array(4).fill(0).map((_, i) => (
                <div key={i} className="rec-skel">
                  <div className="skeleton" style={{ aspectRatio:'3/2', borderRadius: 12, marginBottom: 16 }} />
                  <div className="skeleton" style={{ height: 12, width: '40%', borderRadius: 6, marginBottom: 10 }} />
                  <div className="skeleton" style={{ height: 18, borderRadius: 6, marginBottom: 8 }} />
                  <div className="skeleton" style={{ height: 14, width: '80%', borderRadius: 6 }} />
                </div>
              ))}
            </div>
          )}

          {/* Results grid */}
          {results && !loading && (
            <>
              <div className="rec-results-hdr">
                <div>
                  <h2 className="rec-results-title">Recommended For You</h2>
                  <p className="rec-results-sub">
                    Because you liked <strong>"{query}"</strong>
                  </p>
                </div>
                <span className="rec-results-count">{results.length} books found</span>
              </div>

              <div className="rec-grid">
                {results.map((book, i) => (
                  <RecommendCard key={i} book={book} delay={i * 120} />
                ))}
              </div>
            </>
          )}

          {/* Placeholder */}
          {!results && !loading && !error && (
            <div className="rec-placeholder fade-up">
              <div className="rec-placeholder__visual">
                <span className="rec-placeholder__icon">📚</span>
                <div className="rec-placeholder__ring" />
              </div>
              <h3>Search for any book to begin</h3>
              <p>
                Our AI analyses reading patterns from 270,000+ ratings
                to find books readers like you genuinely loved.
              </p>
            </div>
          )}

        </div>
      </section>

    </div>
  );
}
